// swift-tools-version:5.9
import PackageDescription

let package = Package(
    name: "TheiaPreview",
    platforms: [
        .macOS(.v14)
    ],
    products: [
        .library(
            name: "TheiaSyntax",
            targets: ["TheiaSyntax"]
        ),
        .library(
            name: "TheiaThemes",
            targets: ["TheiaThemes"]
        ),
        .library(
            name: "TheiaEditor",
            targets: ["TheiaEditor"]
        )
    ],
    dependencies: [
        // Syntax highlighting
        .package(url: "https://github.com/apple/swift-syntax.git", from: "509.0.0"),
        // Markdown parsing
        .package(url: "https://github.com/apple/swift-markdown.git", from: "0.3.0"),
        // Tree-sitter for multi-language support
        .package(url: "https://github.com/ChimeHQ/SwiftTreeSitter.git", from: "0.8.0"),
    ],
    targets: [
        .target(
            name: "TheiaSyntax",
            dependencies: [
                .product(name: "SwiftSyntax", package: "swift-syntax"),
                .product(name: "SwiftTreeSitter", package: "SwiftTreeSitter"),
            ]
        ),
        .target(
            name: "TheiaThemes",
            dependencies: [],
            resources: [
                .process("Resources/Themes")
            ]
        ),
        .target(
            name: "TheiaEditor",
            dependencies: [
                "TheiaSyntax",
                "TheiaThemes",
                .product(name: "Markdown", package: "swift-markdown"),
            ]
        ),
        .testTarget(
            name: "TheiaSyntaxTests",
            dependencies: ["TheiaSyntax"]
        ),
        .testTarget(
            name: "TheiaThemesTests",
            dependencies: ["TheiaThemes"]
        ),
        .testTarget(
            name: "TheiaEditorTests",
            dependencies: ["TheiaEditor"]
        ),
    ]
)

