{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://theia-preview.dev/schemas/theme.json",
  "title": "Theia Preview Theme Schema",
  "description": "JSON schema for Theia Preview color themes",
  "type": "object",
  "required": ["name", "type", "colors", "tokenColors"],
  "properties": {
    "name": {
      "type": "string",
      "description": "Display name of the theme"
    },
    "id": {
      "type": "string",
      "pattern": "^[a-z0-9-]+$",
      "description": "Unique identifier (lowercase with hyphens)"
    },
    "type": {
      "type": "string",
      "enum": ["dark", "light", "high-contrast"],
      "description": "Theme type for system appearance matching"
    },
    "author": {
      "type": "string",
      "description": "Theme author name"
    },
    "version": {
      "type": "string",
      "pattern": "^\\d+\\.\\d+\\.\\d+$",
      "description": "Semantic version"
    },
    "colors": {
      "type": "object",
      "description": "Editor and UI colors",
      "properties": {
        "editor": {
          "type": "object",
          "properties": {
            "background": { "$ref": "#/definitions/color" },
            "foreground": { "$ref": "#/definitions/color" },
            "lineHighlight": { "$ref": "#/definitions/color" },
            "selection": { "$ref": "#/definitions/color" },
            "selectionHighlight": { "$ref": "#/definitions/color" },
            "cursor": { "$ref": "#/definitions/color" },
            "cursorLine": { "$ref": "#/definitions/color" }
          },
          "required": ["background", "foreground"]
        },
        "gutter": {
          "type": "object",
          "properties": {
            "background": { "$ref": "#/definitions/color" },
            "foreground": { "$ref": "#/definitions/color" },
            "activeForeground": { "$ref": "#/definitions/color" }
          }
        },
        "scrollbar": {
          "type": "object",
          "properties": {
            "track": { "$ref": "#/definitions/color" },
            "thumb": { "$ref": "#/definitions/color" },
            "thumbHover": { "$ref": "#/definitions/color" }
          }
        },
        "bracket": {
          "type": "object",
          "properties": {
            "match": { "$ref": "#/definitions/color" },
            "mismatch": { "$ref": "#/definitions/color" }
          }
        }
      },
      "required": ["editor"]
    },
    "tokenColors": {
      "type": "array",
      "description": "Syntax highlighting token colors",
      "items": {
        "type": "object",
        "required": ["scope", "settings"],
        "properties": {
          "name": {
            "type": "string",
            "description": "Human-readable name for the rule"
          },
          "scope": {
            "oneOf": [
              { "type": "string" },
              { "type": "array", "items": { "type": "string" } }
            ],
            "description": "TextMate scope(s) to match"
          },
          "settings": {
            "type": "object",
            "properties": {
              "foreground": { "$ref": "#/definitions/color" },
              "background": { "$ref": "#/definitions/color" },
              "fontStyle": {
                "type": "string",
                "enum": ["", "italic", "bold", "bold italic", "underline", "strikethrough"]
              }
            }
          }
        }
      }
    },
    "semanticTokenColors": {
      "type": "object",
      "description": "LSP semantic token colors (optional)",
      "additionalProperties": {
        "oneOf": [
          { "$ref": "#/definitions/color" },
          {
            "type": "object",
            "properties": {
              "foreground": { "$ref": "#/definitions/color" },
              "fontStyle": { "type": "string" }
            }
          }
        ]
      }
    }
  },
  "definitions": {
    "color": {
      "type": "string",
      "pattern": "^#([0-9a-fA-F]{6}|[0-9a-fA-F]{8})$",
      "description": "Hex color (#RRGGBB or #RRGGBBAA)"
    }
  }
}

