// TheiaSyntax - Syntax Highlighting Engine
// Part of Theia Preview - The All-Seeing Developer Preview

import Foundation

/// Main syntax highlighting engine using Tree-sitter parsers
public struct SyntaxEngine {

    /// Supported programming languages
    public enum Language: String, CaseIterable {
        case swift, typescript, javascript, tsx, jsx
        case python, rust, go, ruby, php
        case c, cpp, csharp, java, kotlin
        case json, yaml, toml, xml, html, css, scss
        case markdown, sql, graphql
        case bash, zsh, powershell
        case plainText = "plain"

        /// File extensions mapped to language
        public static func detect(from url: URL) -> Language {
            let ext = url.pathExtension.lowercased()
            switch ext {
            case "swift": return .swift
            case "ts": return .typescript
            case "js": return .javascript
            case "tsx": return .tsx
            case "jsx": return .jsx
            case "py", "pyw": return .python
            case "rs": return .rust
            case "go": return .go
            case "rb": return .ruby
            case "php": return .php
            case "c", "h": return .c
            case "cpp", "cc", "cxx", "hpp": return .cpp
            case "cs": return .csharp
            case "java": return .java
            case "kt", "kts": return .kotlin
            case "json", "jsonc": return .json
            case "yaml", "yml": return .yaml
            case "toml": return .toml
            case "xml", "plist": return .xml
            case "html", "htm": return .html
            case "css": return .css
            case "scss", "sass": return .scss
            case "md", "mdx", "markdown": return .markdown
            case "sql": return .sql
            case "graphql", "gql": return .graphql
            case "sh", "bash": return .bash
            case "zsh": return .zsh
            case "ps1": return .powershell
            default: return .plainText
            }
        }
    }

    public init() {}

    /// Highlight source code with the given theme
    /// - Parameters:
    ///   - content: Source code string
    ///   - language: Programming language
    ///   - theme: Color theme to apply
    /// - Returns: Attributed string with syntax highlighting
    public func highlight(_ content: String, language: Language, theme: Theme) async throws -> NSAttributedString {
        // TODO: Implement Tree-sitter parsing
