import Foundation

/// Manages loading, caching, and switching themes
public class ThemeManager {

    /// Shared instance
    public static let shared = ThemeManager()

    /// Currently active theme
    public private(set) var currentTheme: Theme

    /// All available themes (built-in + custom)
    public private(set) var availableThemes: [Theme] = []

    /// User defaults key for selected theme
    private let selectedThemeKey = "selectedTheme"

    /// Custom themes directory
    private var customThemesURL: URL? {
        FileManager.default.urls(for: .applicationSupportDirectory, in: .userDomainMask).first?
            .appendingPathComponent("TheiaPreview")
            .appendingPathComponent("Themes")
    }

    private init() {
        // Load default theme
        self.currentTheme = Self.defaultTheme

        // Load all themes
        Task {
            await loadAllThemes()

            // Restore user's selected theme
            if let savedThemeId = UserDefaults.standard.string(forKey: selectedThemeKey),
               let savedTheme = availableThemes.first(where: { $0.id == savedThemeId }) {
                self.currentTheme = savedTheme
            }
        }
    }

    /// Load all available themes
    public func loadAllThemes() async {
        var themes: [Theme] = []

        // Load built-in themes from bundle
        if let builtInThemes = loadBuiltInThemes() {
            themes.append(contentsOf: builtInThemes)
        }

        // Load custom themes from user directory
        if let customThemes = loadCustomThemes() {
            themes.append(contentsOf: customThemes)
        }

        // Sort by name
        availableThemes = themes.sorted { $0.name < $1.name }
    }

    /// Switch to a different theme
    public func switchTheme(to id: String) {
        guard let theme = availableThemes.first(where: { $0.id == id }) else {
            return
        }
        currentTheme = theme
        UserDefaults.standard.set(id, forKey: selectedThemeKey)

        // Post notification for UI updates
        NotificationCenter.default.post(name: .themeDidChange, object: theme)
    }

    /// Load a theme from a JSON file URL
    public func loadTheme(from url: URL) throws -> Theme {
        let data = try Data(contentsOf: url)
        let decoder = JSONDecoder()
        return try decoder.decode(Theme.self, from: data)
    }

    // MARK: - Private

    private func loadBuiltInThemes() -> [Theme]? {
        guard let resourceURL = Bundle.main.resourceURL?
            .appendingPathComponent("Themes") else {
            return nil
        }

        return loadThemes(from: resourceURL)
    }

    private func loadCustomThemes() -> [Theme]? {
        guard let url = customThemesURL else { return nil }

        // Create directory if it doesn't exist
        try? FileManager.default.createDirectory(at: url, withIntermediateDirectories: true)

        return loadThemes(from: url)
    }

    private func loadThemes(from directory: URL) -> [Theme]? {
        guard let files = try? FileManager.default.contentsOfDirectory(
            at: directory,
            includingPropertiesForKeys: nil
        ) else {
            return nil
        }

        return files
            .filter { $0.pathExtension == "json" }
            .compactMap { try? loadTheme(from: $0) }
    }

    /// Default fallback theme
    private static var defaultTheme: Theme {
        Theme(
            name: "Default",
            id: "default",
            type: .dark,
            colors: ThemeColors(
                editor: EditorColors(
                    background: "#1e1e1e",
                    foreground: "#d4d4d4",
                    lineHighlight: "#2d2d2d",
                    selection: "#264f78",
                    selectionHighlight: nil,
                    cursor: "#ffffff",
                    cursorLine: nil
                ),
                gutter: nil,
                scrollbar: nil,
                bracket: nil
            ),
            tokenColors: []
        )
    }
}

