// MARK: - Notifications

extension Notification.Name {
    public static let themeDidChange = Notification.Name("ThemeDidChange")
}

// TheiaEditor - Inline Editor Component
// Part of Theia Preview - The All-Seeing Developer Preview

import AppKit
import TheiaSyntax
import TheiaThemes

/// Custom text view for syntax-highlighted editing
public class TheiaTextView: NSTextView {

    /// Whether editing is enabled
    public var isEditingEnabled: Bool = false {
        didSet {
            isEditable = isEditingEnabled
            isSelectable = true
        }
    }

    /// Syntax highlighting engine
    public var syntaxEngine: SyntaxEngine = SyntaxEngine()

    /// Current language for highlighting
    public var language: SyntaxEngine.Language = .plainText

    /// Current color theme
    public var theme: Theme = ThemeManager.shared.currentTheme {
        didSet {
            applyTheme()
        }
    }

    /// Show line numbers
    public var showLineNumbers: Bool = true {
        didSet {
            updateRuler()
        }
    }

    /// Highlight current line
    public var highlightCurrentLine: Bool = true

    // MARK: - Initialization

    public override init(frame frameRect: NSRect, textContainer container: NSTextContainer?) {
        super.init(frame: frameRect, textContainer: container)
        commonInit()
    }

    public required init?(coder: NSCoder) {
        super.init(coder: coder)
        commonInit()
    }

    private func commonInit() {
        // Configure text view
        font = NSFont.monospacedSystemFont(ofSize: 13, weight: .regular)
        isRichText = false
        allowsUndo = true
        isAutomaticQuoteSubstitutionEnabled = false
        isAutomaticDashSubstitutionEnabled = false
        isAutomaticTextReplacementEnabled = false
        isAutomaticSpellingCorrectionEnabled = false

        // Apply theme
        applyTheme()

        // Observe theme changes
        NotificationCenter.default.addObserver(
            self,
            selector: #selector(themeDidChange(_:)),
            name: .themeDidChange,
            object: nil
        )
    }

    deinit {
        NotificationCenter.default.removeObserver(self)
    }

    // MARK: - Theme

    private func applyTheme() {
        if let bgColor = NSColor(hex: theme.colors.editor.background) {
            backgroundColor = bgColor
        }
        if let fgColor = NSColor(hex: theme.colors.editor.foreground) {
            insertionPointColor = fgColor
        }

        // Re-highlight content
        Task {
            await rehighlight()
        }
    }

    @objc private func themeDidChange(_ notification: Notification) {
        if let newTheme = notification.object as? Theme {
            theme = newTheme
        }
    }

    // MARK: - Syntax Highlighting

    /// Re-highlight the entire content
    public func rehighlight() async {
        guard let content = string as String?, !content.isEmpty else { return }

        do {
            let highlighted = try await syntaxEngine.highlight(content, language: language, theme: theme)

            await MainActor.run {
                // Preserve selection
                let selectedRange = self.selectedRange()

                // Replace content
                textStorage?.setAttributedString(highlighted)

                // Restore selection
                if selectedRange.location <= string.count {
                    setSelectedRange(selectedRange)
                }
            }
        } catch {
            print("Syntax highlighting error: \(error)")
        }
    }

    // MARK: - Editing

    public override func didChangeText() {
        super.didChangeText()

        // Trigger re-highlighting
        Task {
            await rehighlight()
        }
    }

    // MARK: - Line Numbers

    private func updateRuler() {
        if showLineNumbers {
            enclosingScrollView?.rulersVisible = true
            // TODO: Implement line number ruler view
        } else {
            enclosingScrollView?.rulersVisible = false
        }
    }

    // MARK: - Current Line Highlighting

    public override func drawBackground(in rect: NSRect) {
        super.drawBackground(in: rect)

        guard highlightCurrentLine,
              let layoutManager = layoutManager,
              let textContainer = textContainer else {
            return
        }

        // Get current line rect
        let selectedRange = self.selectedRange()
        let glyphRange = layoutManager.glyphRange(
            forCharacterRange: selectedRange,
            actualCharacterRange: nil
        )
        var lineRect = layoutManager.boundingRect(
            forGlyphRange: glyphRange,
            in: textContainer
        )
        lineRect.origin.x = 0
        lineRect.size.width = bounds.width

        // Draw highlight
        if let highlightColor = NSColor(hex: theme.colors.editor.lineHighlight ?? theme.colors.editor.background)?
            .withAlphaComponent(0.5) {
            highlightColor.setFill()
            lineRect.fill()
        }
    }
}
